apps.compose:
services:
  app:
    image: ghcr.io/hasan-ismail/openmasjid-announcements-board:1.0.0
    restart: unless-stopped
    environment:
      MASJID_NAME: ${MASJID_NAME}
      ANN1_TITLE: ${ANN1_TITLE}
      ANN1_TEXT: ${ANN1_TEXT}
      ANN2_TITLE: ${ANN2_TITLE}
      ANN2_TEXT: ${ANN2_TEXT}
      ANN3_TITLE: ${ANN3_TITLE}
      ANN3_TEXT: ${ANN3_TEXT}
      ANN4_TITLE: ${ANN4_TITLE}
      ANN4_TEXT: ${ANN4_TEXT}
      ANN5_TITLE: ${ANN5_TITLE}
      ANN5_TEXT: ${ANN5_TEXT}
      ANN6_TITLE: ${ANN6_TITLE}
      ANN6_TEXT: ${ANN6_TEXT}
      ROTATE_SECONDS: ${ROTATE_SECONDS}
      FOOTER_NOTE: ${FOOTER_NOTE}
      SHOW_TIME: ${SHOW_TIME}
      TIME_FORMAT: ${TIME_FORMAT}
      TIMEZONE: ${TIMEZONE}
      LANGUAGE: ${LANGUAGE}
    ports:
      # host:container — the platform offers "Open" on the published host port and
      # will pick a different free host port automatically if 8732 is taken.
      - "8732:80"

services:
  app:
    image: ghcr.io/hasan-ismail/openmasjid-prayer-times-display:1.0.0
    restart: unless-stopped
    environment:
      MASJID_NAME: ${MASJID_NAME}
      LATITUDE: ${LATITUDE}
      LONGITUDE: ${LONGITUDE}
      CALC_METHOD: ${CALC_METHOD}
      ASR_MADHAB: ${ASR_MADHAB}
      TIMEZONE: ${TIMEZONE}
      TIME_FORMAT: ${TIME_FORMAT}
      SCREEN_ORIENTATION: ${SCREEN_ORIENTATION}
      LANGUAGE: ${LANGUAGE}
    ports:
      # host:container — the platform offers "Open" on the published host port and
      # will pick a different free host port automatically if 8731 is taken.
      - "8731:80"
